import React from "react";
import "./About.css";

export default function About() {
  const heroImg =
    "https://static.vecteezy.com/system/resources/thumbnails/019/050/491/small/a-girl-sitting-and-writing-a-diet-plan-weight-loss-concept-eat-food-that-is-good-for-the-body-such-as-fruits-and-vegetables-free-photo.jpg";

  const items = [
    {
      title: "Healthy Planning",
      desc: "Organize meals",
    },
    {
      title: "Balanced Diets",
      desc: "Science-backed",
    },
    {
      title: "Expert Support",
      desc: "Guided advice",
    },
    {
      title: "Smart Tracking",
      desc: "Progress updates",
    },
  ];

  return (
    <div className="about-bg">

      {/* MAIN GLASS HERO SECTION */}
      <div className="about-hero-card">

        {/* TOP NAV INSIDE CARD (LIKE THE REFERENCE) */}
        <div className="card-navbar">
          <span className="brand">NutriPlan</span>
          <div className="nav-links">
            <a href="/">Home</a>
            <a href="/create-plan">Plans</a>
            <a href="/nutrition-info">Nutrition</a>
            <a href="/about" className="active-nav">About</a>
          </div>
        </div>

        {/* MAIN CONTENT */}
        <div className="hero-content">
          <div className="hero-left">
            <p className="small-label">ABOUT US 🌿</p>

            <h1>
              Build Healthier Habits<br />One Step at a Time
            </h1>

            <p className="hero-desc">
              We help individuals achieve better health with personalized diet plans,
              balanced meals, and simple wellness strategies. Our platform combines
              science-based nutrition with real-world practicality — making healthy
              living easier, enjoyable, and sustainable.
            </p>

            <div className="hero-btns">
              <button className="btn-filled">Learn More</button>
              <button className="btn-outline">Why Choose Us?</button>
            </div>
          </div>

          <div className="hero-right">
            <img src={heroImg} alt="Diet Plan" />
          </div>
        </div>
      </div>

      {/* BOTTOM MINI CARDS (LIKE THE REFERENCE MENU ITEMS) */}
      <div className="bottom-items">
        {items.map((it, index) => (
          <div className="item-card" key={index}>
            <h3>{it.title}</h3>
            <p>{it.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
